    16→/**
    17→ * List of templates that have page-specific CSS files
    18→ * Template names match both $class_names[] in page templates and compiled CSS filenames
    19→ */
    20→define('HONE_PAGE_TEMPLATES', [
    21→    'article-trt',
    22→    'article-trt-new-copy',
    23→    'article-trt-old-design-new-copy',
    24→    'basic-membership',
    25→    'basic-membership-v2',
