    39→// Enqueue styles and scripts
    40→function hone_landing_enqueue_assets() {
    41→    global $class_names;
    42→
    43→    $theme_version = wp_get_theme()->get('Version');
    44→    $theme_uri = get_template_directory_uri();
    45→
    46→    // Always load main.min.css - contains all common styles (reset, settings, parts)
    47→    wp_enqueue_style(
    48→        'hone-main-style',
    49→        $theme_uri . '/static/css/main.min.css',
    50→        array(),
    51→        $theme_version
    52→    );
    53→
    54→    // Early return if no class_names set
    55→    if (empty($class_names) || !is_array($class_names)) {
    56→        return;
    57→    }
    58→
    59→    // Check if this template has page-specific styles
    60→    $matches = array_intersect($class_names, HONE_PAGE_TEMPLATES);
    61→
    62→    // Load all matching page-specific styles in order
    63→    // This allows for layered styles (e.g., base 'mens-hrt-aol' + specific 'mens-hrt-aol-forbes')
    64→    if (!empty($matches)) {
    65→        $dependencies = array('hone-main-style'); // First match depends on main styles
    66→        
    67→        foreach ($matches as $matched_class) {
    68→            $css_file = get_template_directory() . '/static/css/pages/' . $matched_class . '.css';
    69→            if (file_exists($css_file)) {
    70→                wp_enqueue_style(
    71→                    'hone-page-' . $matched_class,
    72→                    $theme_uri . '/static/css/pages/' . $matched_class . '.css',
    73→                    $dependencies,
    74→                    $theme_version,
    75→                    'all'
    76→                );
    77→                // Make next stylesheet depend on this one to maintain load order
    78→                $dependencies = array('hone-page-' . $matched_class);
    79→            }
    80→        }
    81→    }
    82→    
    83→    // Enqueue main JavaScript (always loaded - contains trackQuizEvent)
    84→    wp_enqueue_script(
    85→        'hone-main-script',
    86→        $theme_uri . '/static/js/dist/combined.js',
    87→        array(),
    88→        $theme_version,
    89→        true
    90→    );
    91→}
    92→add_action('wp_enqueue_scripts', 'hone_landing_enqueue_assets');
    93→
    94→/**
    95→ * Register page-specific JavaScript bundles
    96→ * 
    97→ * These bundles are built with esbuild and include all dependencies
    98→ * (except jQuery which is loaded via WordPress).
    99→ * 
   100→ * Each bundle includes: Slick carousel + relevant utilities
   101→ * 
   102→ * Usage in templates:
   103→ *   wp_enqueue_script('hone-page-article-trt-new-copy');
   104→ */
   105→function hone_register_bundles() {
   106→    $theme_version = wp_get_theme()->get('Version');
   107→    $theme_uri = get_template_directory_uri();
   108→    $theme_dir = get_template_directory();
   109→    
   110→    // Register jQuery Migrate (dependency for Slick)
   111→    wp_register_script(
   112→        'jquery-migrate',
   113→        $theme_uri . '/static/js/dist/jquery-migrate-1.2.1.min.js',
   114→        array('jquery'),
   115→        '1.2.1',
   116→        true
   117→    );
   118→    
   119→    // Register Slick carousel
   120→    wp_register_script(
   121→        'slick-carousel',
   122→        $theme_uri . '/static/js/dist/slick.min.js',
   123→        array('jquery', 'jquery-migrate'),
   124→        '1.8.1',
   125→        true
   126→    );
   127→    
   128→    // Register each page bundle with jQuery, jQuery Migrate, and Slick as dependencies
   129→    foreach (HONE_PAGE_TEMPLATES as $page) {
   130→        $bundle_path = $theme_dir . '/static/js/dist/pages/' . $page . '.bundle.min.js';
   131→        $bundle_url = $theme_uri . '/static/js/dist/pages/' . $page . '.bundle.min.js';
   132→        if (file_exists($bundle_path)) {
   133→            wp_register_script(
   134→                'hone-page-' . $page,
   135→                $bundle_url,
   136→                array('jquery', 'jquery-migrate', 'slick-carousel'),
   137→                $theme_version,
   138→                true
   139→            );
   140→        }
   141→    }
   142→}
   143→add_action('wp_enqueue_scripts', 'hone_register_bundles', 5);
   144→
   145→// the current LPs had funky urls and we need to match them exactly so that the ads don't get reset
   146→// The pages in wp-admin need to be set with these specific slugs and cannot have a parent page.
   147→remove_filter('template_redirect', 'redirect_canonical');
   148→add_action('init', function() {
   149→    add_rewrite_rule('^overview/3/?$', 'index.php?pagename=overview-3', 'top');
   150→    add_rewrite_rule('^overview/3/hormone-optimization/?$', 'index.php?pagename=overview-3-hormone-optimization', 'top');    
   151→    add_rewrite_rule('^overview/3/rww/tiktok/?$', 'index.php?pagename=overview-tiktok', 'top');        
   152→});
   153→
   154→add_filter('query_vars', function($vars) {
   155→    $vars[] = 'pagename';
   156→    return $vars;
   157→});
   158→
   159→function get_query_string(){
   160→    $query_params = [];
   161→    foreach ($_GET as $key => $value) {
   162→        $query_params[$key] = sanitize_text_field($value);
   163→    }
   164→    return http_build_query($query_params);
   165→}
