     1→import esbuild from 'esbuild';
     2→import { glob } from 'glob';
     3→import path from 'path';
     4→
     5→async function build() {
     6→  try {
     7→    /**
     8→     * ===============================
     9→     * Build the main combined js
    10→     * ===============================
    11→     */
    12→    // Build the main combined.js (trackQuizEvent only, for backward compatibility)
    13→    await esbuild.build({
    14→      bundle: true,
    15→      minify: true,
    16→      sourcemap: false,
    17→      format: 'iife',
    18→      entryPoints: ['src/static/js/index.js'],
    19→      outfile: 'src/static/js/dist/combined.js',
    20→    });
    21→    console.log('✓ Built combined.js');
    22→
    23→    /**
    24→     * ===============================
    25→     * Build the page bundles
    26→     * ===============================
    27→     */
    28→    // Find all bundle entry points
    29→    const bundleFiles = await glob('src/static/js/pages/*.bundle.js');
    30→    
    31→    // Build each page bundle
    32→    for (const bundleFile of bundleFiles) {
    33→      const filename = path.basename(bundleFile, '.bundle.js');
    34→      await esbuild.build({
    35→        bundle: true,
    36→        minify: true,
    37→        sourcemap: false,
    38→        format: 'iife',
    39→        entryPoints: [bundleFile],
    40→        outfile: `src/static/js/dist/pages/${filename}.bundle.min.js`,
    41→        external: ['jquery'],
    42→      });
    43→      console.log(`✓ Built ${filename}.bundle.min.js`);
    44→    }
    45→
    46→    console.log('\n🎉 All bundles built successfully!');
    47→  } catch (err) {
    48→    console.error('esbuild failed:', err);
    49→    process.exit(1);
    50→  }
    51→}
    52→
    53→build();

