     1→const fs = require('fs-extra');
     2→const path = require('path');
     3→const { execSync } = require('child_process');
     4→
     5→// Paths
     6→const srcDir = path.resolve(__dirname, 'src');
     7→const buildDir = path.resolve(__dirname, 'build');
     8→
     9→// Helper function to run shell commands
    10→function runCommand(command) {
    11→  try {
    12→    console.log(`Running: ${command}`);
    13→    execSync(command, { stdio: 'inherit' });
    14→  } catch (error) {
    15→    console.error(`Error running command: ${command}`);
    16→    process.exit(1);
    17→  }
    18→}
    19→
    20→// Clean the build directory
    21→console.log('Cleaning build directory...');
    22→fs.emptyDirSync(buildDir);
    23→
    24→// Run asset build steps
    25→console.log('Building CSS/JS assets...');
    26→runCommand('yarn build:assets');
    27→
    28→// Copy theme files (excluding scss, static/js/index.js, and static/js/modules directory)
    29→console.log('Copying theme files...');
    30→fs.copySync(srcDir, buildDir, {
    31→  filter: (src) => {
    32→    const normalizedSrc = path.normalize(src);
    33→
    34→    return (
    35→      !normalizedSrc.endsWith('.scss') &&
    36→      !normalizedSrc.includes(path.join('static', 'scss')) &&
    37→      !normalizedSrc.includes(path.join('static', 'js', 'modules')) &&
    38→      !normalizedSrc.endsWith(path.join('static', 'js', 'index.js'))
    39→    );
    40→  },
    41→});
    42→
    43→console.log('Build complete!');

